bool Model::load(Arena& arena)
{
    CmsisNnQuant::FinalizeConv2DPlan(kConv0Plan);
    CmsisNnQuant::FinalizeDepthwiseConv2DPlan(kDw1Plan);
    CmsisNnQuant::FinalizePool2DPlan(kPool2Plan);
    CmsisNnQuant::FinalizeConv2DPlan(kConv2Plan);
    CmsisNnQuant::FinalizeDepthwiseConv2DPlan(kDw3Plan);
    CmsisNnQuant::FinalizePool2DPlan(kPool5Plan);
    CmsisNnQuant::FinalizeFcPlan(kFc4Plan, kW4, kB4, arena);
    CmsisNnQuant::FinalizeFcPlan(kFc5Plan, kW5, kB5, arena);
    loaded_ = true;
    return true;
}

bool Model::forwardInt8(Arena& /*arena*/, const int8_t* input, int8_t* output) const
{
    if (!loaded_ || !input || !output)
        return false;
    KernelWorkspace workspace{g_workspace, kWorkspaceBytes};
    KernelWorkspaceScope workspace_scope(&workspace);
    const int8_t* current = input;
    int8_t* slot_a = g_act_a;
    int8_t* slot_b = g_act_b;
    bool use_a = true;

    if (use_a) {
        if (!CmsisNnQuant::TryConv2dNhwcQuantPlan(
                kConv0Plan, current, kW0, kB0, slot_a))
            return false;
        current = slot_a;
    } else {
        if (!CmsisNnQuant::TryConv2dNhwcQuantPlan(
                kConv0Plan, current, kW0, kB0, slot_b))
            return false;
        current = slot_b;
    }
    use_a = !use_a;

    if (use_a) {
        if (!CmsisNnQuant::TryDepthwiseConv2dNhwcQuantPlan(
                kDw1Plan, current, kW1Hwc, kB1, slot_a))
            return false;
        current = slot_a;
    } else {
        if (!CmsisNnQuant::TryDepthwiseConv2dNhwcQuantPlan(
                kDw1Plan, current, kW1Hwc, kB1, slot_b))
            return false;
        current = slot_b;
    }
    use_a = !use_a;

    if (use_a) {
        if (!CmsisNnQuant::TryMaxPool2dNhwcQuantPlan(kPool2Plan, current, slot_a))
            return false;
        current = slot_a;
    } else {
        if (!CmsisNnQuant::TryMaxPool2dNhwcQuantPlan(kPool2Plan, current, slot_b))
            return false;
        current = slot_b;
    }
    use_a = !use_a;

    if (use_a) {
        if (!CmsisNnQuant::TryConv2dNhwcQuantPlan(
                kConv2Plan, current, kW2, kB2, slot_a))
            return false;
        current = slot_a;
    } else {
        if (!CmsisNnQuant::TryConv2dNhwcQuantPlan(
                kConv2Plan, current, kW2, kB2, slot_b))
            return false;
        current = slot_b;
    }
    use_a = !use_a;

    if (use_a) {
        if (!CmsisNnQuant::TryDepthwiseConv2dNhwcQuantPlan(
                kDw3Plan, current, kW3Hwc, kB3, slot_a))
            return false;
        current = slot_a;
    } else {
        if (!CmsisNnQuant::TryDepthwiseConv2dNhwcQuantPlan(
                kDw3Plan, current, kW3Hwc, kB3, slot_b))
            return false;
        current = slot_b;
    }
    use_a = !use_a;

    if (use_a) {
        if (!CmsisNnQuant::TryMaxPool2dNhwcQuantPlan(kPool5Plan, current, slot_a))
            return false;
        current = slot_a;
    } else {
        if (!CmsisNnQuant::TryMaxPool2dNhwcQuantPlan(kPool5Plan, current, slot_b))
            return false;
        current = slot_b;
    }
    use_a = !use_a;

    // flatten: zero-copy view (current unchanged)

    if (use_a) {
        if (!CmsisNnQuant::TryFullyConnectedQuantPlan(
                kFc4Plan, current, kW4, kB4, slot_a))
            return false;
        current = slot_a;
    } else {
        if (!CmsisNnQuant::TryFullyConnectedQuantPlan(
                kFc4Plan, current, kW4, kB4, slot_b))
            return false;
        current = slot_b;
    }
    use_a = !use_a;

    if (!CmsisNnQuant::TryFullyConnectedQuantPlan(
            kFc5Plan, current, kW5, kB5, output))
        return false;
    return true;

    return true;

}

